#include <bits/stdc++.h>
using namespace std;
const int N=20;
int n,m,dp[N][N],a[N][N],num[N][N];
string ans[N];
int main()
{
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++) cin>>a[i][j];
    }
    memset(dp,128,sizeof(dp));
    dp[0][m]=0;
    for(int i=1;i<=n;i++)
    {
        for(int k=0;k<=m;k++)//差
        {
            for(int j=k;j<=m;j++)//之前的
            {
                int numnew=j-k;
                int t=dp[i-1][j]+a[i][k];
                if(t>=dp[i][numnew])
                {
                    dp[i][numnew]=t;
                    num[i][numnew]=j;
                }
            }
        }
    }
    // for(int i=1;i<=n;i++)
    // {
    //     for(int j=0;j<=m;j++) cout<<dp[i][j]<<" ";
    //     cout<<'\n';
    // }
    cout<<dp[n][0]<<'\n';

    string s;
    int t=0;
    for(int i=n;i>0;i--)
    {
        int t2=num[i][t];
        ans[i]=to_string(i)+" "+to_string(t2-t);
        t=t2;
    }
    for(int i=1;i<=n;i++) cout<<ans[i]<<'\n';
    return 0;
}
